INSERT INTO `abouts` (`id`, `short`, `content`, `created_at`, `updated_at`) VALUES
(1, 'ToolsGPT is a privacy-first web utilities platform dedicated to delivering professional-grade files and image management tools that operate locally within your browser sandbox.', '<h2 class=\"text-xl font-space font-bold text-slate-800\">Complete Privacy</h2>\n<p>All operations run in local browser memory. Since no files are uploaded to our servers, your sensitive data remains completely private and secure under your direct control.</p>\n<h2 class=\"text-xl font-space font-bold text-slate-800\">High-Performance WASM Engine</h2>\n<p>By compiling optimized file processing algorithms into WebAssembly (WASM), we deliver instant offline processing speeds directly inside your browser.</p>\n<h2 class=\"text-xl font-space font-bold text-slate-800\">No Constraints</h2>\n<p>ToolsGPT is free to use without registrations, subscription paywalls, or daily upload caps. Enjoy unlimited features directly on your machine.</p>\n<h2 class=\"text-xl font-space font-bold text-slate-800\">Modern Client-Side Architecture</h2>\n<p>By offloading all computation from cloud servers to your local client device, we eliminate server bandwidth costs. This enables us to maintain a 100% free model without requiring user profiles, API subscriptions, or data collection.</p>\n<h3 class=\"text-lg font-space font-semibold text-slate-800\">Core Technologies:</h3>\n<ul class=\"list-disc pl-5 space-y-1\">\n<li><strong>WebAssembly:</strong>&nbsp;Fast, local file processing algorithms.</li>\n<li><strong>HTML5 Canvas:</strong>&nbsp;Rich, client-side rendering and manipulation.</li>\n<li><strong>Laravel &amp; TailwindCSS:</strong>&nbsp;Secure backend routing and clean user interface.</li>\n</ul>\n<div class=\"mt-4 p-4 bg-indigo-50 border border-indigo-100 rounded text-indigo-900 font-semibold\">🛡️ 100% Client-Side Processing: Zero files touch our cloud servers. Ever.</div>', '2026-07-06 16:31:18', '2026-07-06 16:33:40');

